ion.turn_desc\"\r\n                                ></el-option>\r\n                            </el-select>\r\n\r\n                            <small\r\n                                class=\"form-control-feedback\"\r\n                                v-if=\"errors.reference_number\"\r\n                                v-text=\"errors.reference_number[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n            <div class=\"form-actions text-end pt-2 pb-2\">\r\n                <el-button @click.prevent=\"close()\">Cancelar</el-button>\r\n                <el-button\r\n                    type=\"primary\"\r\n                    native-type=\"submit\"\r\n                    :loading=\"loading_submit\"\r\n                    >Guardar</el-button\r\n                >\r\n            </div>\r\n        </form>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\nexport default {\r\n    props: [\"showDialog\", \"recordId\", \"typeUser\", \"fromBox\"],\r\n    data() {\r\n        return {\r\n            loading_submit: false,\r\n            titleDialog: null,\r\n            resource: \"restaurant/worker/cash\",\r\n            errors: {},\r\n            form: {},\r\n            user: {},\r\n            all_departments: [],\r\n            all_provinces: [],\r\n            all_districts: [],\r\n            provinces: [],\r\n            districts: [],\r\n            identity_document_types: [],\r\n            users: [],\r\n            turnsTable: [],\r\n            dontClose: false\r\n        };\r\n    },\r\n    async created() {\r\n        await this.$http.get(`/${this.resource}/tables`).then(response => {\r\n            this.users = response.data.users;\r\n            this.user = response.data.user;\r\n            this.turnsTable = response.data.turnsTable;\r\n        });\r\n\r\n        this.initForm();\r\n    },\r\n    computed: {\r\n        disableUser() {\r\n            if (this.typeUser == \"admin\" || this.typeUser === \"superadmin\") {\r\n                return false;\r\n            }\r\n            return true;\r\n        }\r\n    },\r\n    methods: {\r\n        ocultarBoton() {\r\n            this.$emit(\"ocultarBoton\");\r\n        },\r\n\r\n        initForm() {\r\n            this.errors = {};\r\n            this.form = {\r\n                id: null,\r\n                user_id: this.user.id,\r\n                // user: null,\r\n                date_opening: null,\r\n                time_opening: null,\r\n                date_closed: null,\r\n                time_closed: null,\r\n                beginning_balance: 0,\r\n                final_balance: 0,\r\n                income: 0,\r\n                state: true,\r\n                reference_number: null\r\n            };\r\n        },\r\n        create() {\r\n            this.titleDialog = this.recordId ? \"Editar Caja\" : \"Aperturar Caja\";\r\n            if (this.recordId) {\r\n                this.$http\r\n                    .get(`/${this.resource}/record/${this.recordId}`)\r\n                    .then(response => {\r\n                        this.form = response.data.data;\r\n                    });\r\n            } else {\r\n                this.form.user_id = this.user.id; //sesion\r\n                //this.form.user = this.user.name\r\n            }\r\n        },\r\n        async openingCashCkeck() {\r\n            let response = await this.$http.get(\r\n                `/${this.resource}/opening_cash_check/${this.form.user_id}`\r\n            );\r\n\r\n            let cash = response.data.cash;\r\n            return cash ? true : false;\r\n        },\r\n        async submit() {\r\n            this.loading_submit = true;\r\n\r\n            if (this.form.turn_id == undefined) {\r\n                this.$toast.warning(\r\n                    `La opcion 'Seleccionar turno de apertura' no puede ser un campo vacio, por favor seleccione una opcion`\r\n                );\r\n\r\n                this.loading_submit = false;\r\n                return false;\r\n            }\r\n            if (!this.recordId) {\r\n                if (await this.openingCashCkeck()) {\r\n                    this.$toast.warning(\r\n                        \"No puede crear caja, porfavor cierre caja para el usuario definido\"\r\n                    );\r\n\r\n                    this.loading_submit = false;\r\n                    return false;\r\n                }\r\n            }\r\n\r\n            this.$http\r\n                .post(`/${this.resource}`, this.form)\r\n                .then(response => {\r\n                    console.log(response);\r\n                    if (response.data.success) {\r\n                        this.$toast.success(response.data.message);\r\n                        if (this.form.user_id === this.user.id)\r\n                            this.$eventHub.$emit(\"openCash\");\r\n                        this.$eventHub.$emit(\"reloadData\");\r\n                        if (this.fromBox) {\r\n                            this.$emit(\"updateCashId\", response.data.cash_id);\r\n                        }\r\n                        // window.open('/pos/init')\r\n                        this.close();\r\n                        this.ocultarBoton();\r\n                    } else {\r\n                        this.$toast.error(response.data.message);\r\n                    }\r\n                })\r\n                .catch(error => {\r\n                    if (error.response.status === 422) {\r\n                        this.errors = error.response.data;\r\n                    } else {\r\n                        console.log(error);\r\n                    }\r\n                })\r\n                .then(() => {\r\n                    this.loading_submit = false;\r\n                });\r\n        },\r\n        close() {\r\n            this.$emit(\"update:showDialog\", false);\r\n            this.initForm();\r\n        }\r\n    }\r\n};\r\n</script